const heat = require('./data/heat_classification.json');
const dash = require('./output/.dashboard_snapshot.json');

// 清理null
const hNames = new Set(heat.results.map(r => (r.name||'').toLowerCase().trim()).filter(Boolean));
const dNames = new Set(dash.customers.map(r => (r.name||'').toLowerCase().trim()).filter(Boolean));

let match = 0, noMatch = 0;
for (const r of heat.results) {
  const key = (r.name||'').toLowerCase().trim();
  if (!key) { noMatch++; continue; }
  if (dNames.has(key)) match++;
  else noMatch++;
}
console.log('仅用name匹配:', match, '/', heat.results.length, '=', (match/heat.results.length*100).toFixed(1)+'%');

// 用 name+country 匹配
let match2 = 0, noMatch2 = 0;
for (const r of heat.results) {
  const key = (r.name||'').toLowerCase().trim() + '|' + (r.country||'').toUpperCase().trim();
  if (!r.name) { noMatch2++; continue; }
  const found = dash.customers.find(d => (d.name||'').toLowerCase().trim() === (r.name||'').toLowerCase().trim() && (d.country||'') === (r.country||''));
  if (found) match2++;
  else noMatch2++;
}
console.log('用name+country匹配:', match2, '/', heat.results.length, '=', (match2/heat.results.length*100).toFixed(1)+'%');

// S级追踪
const sTier = dash.customers.filter(c => c.quality === 'S');
console.log('dashboard S级:', sTier.length);
const sNames = new Set(sTier.map(c => (c.name||'').toLowerCase().trim()));
let sMatched = 0;
for (const r of heat.results) {
  if (sNames.has((r.name||'').toLowerCase().trim())) sMatched++;
}
console.log('S级在heat中匹配:', sMatched);

