  const days = daysBetween(parseDate(bl.S5b), t);
  if (days >= 1) factors.push({ factor: 'S5b 该要地址了', days, priority: 'normal' });
} else if (meta.has_address === null && bl.S5b) {
  // 未知状态 → >30天才弱提醒
  const days = daysBetween(parseDate(bl.S5b), t);
  if (days > 30) {
    factors.push({ factor: 'S5b 该确认地址状态了', days, priority: 'low', note: '未知是否有地址，请人工确认' });
  }
}
// has_address === true → 跳过
```

### Fix-H: _tier_source 实现落地

**审2 判断**：方案提了 `_tier_source` 但没写在哪里写入。

**同意。** 修订实现：

```
// getTier() 改为返回 { tier, source }
function getTierWithSource(name, country) {
  const map = loadTierMap();
  const key = (name || '').toLowerCase().trim() + '|' + (country || '').toUpperCase().trim();
  const matched = map.get(key);
  if (matched) return { tier: matched, source: 'dashboard_snapshot' };
  return { tier: 'C', source: 'default_C' };
}

// init meta 处
const tierInfo = getTierWithSource(c.name, c.country);
meta.customer_tier = tierInfo.tier;
meta._tier_source = tierInfo.source;
```

