// S5b 触发逻辑（computeFactors 待发货 case 内）
if (meta.has_address === false && bl.S5b) {
  // 确认无地址 → 正式催要
  const days = daysBetween(parseDate(bl.S5b), t);
  if (days >= 1) factors.push({ factor: 'S5b 该要地址了', days, priority: 'normal' });
} else if (meta.has_address === null && bl.S5b) {
  // 未知状态 → >30天才弱提醒
  const days = daysBetween(parseDate(bl.S5b), t);
  if (days > 30) {
    factors.push({ factor: 'S5b 该确认地址状态了', days, priority: 'low', note: '未知是否有地址，请人工确认' });
  }
}
// has_address === true → 跳过
```

